29	  it.todo("single staff (no modifiers, first contract) → premium 93 G (80 + 8 + 5)");
30	  it.todo("single potion (no modifiers, first contract) → premium 49 G (40 + 4 + 5)");
31	
32	  // --- Components base premiums ---
33	  it.todo("2 runes → base 50 G");
34	  it.todo("3 runes (block) → base 60 G");
35	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
36	  it.todo("7 runes → base 175 G");
37	
38	  // --- Alike components ---
39	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
40	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
41	
42	  // --- Item-specific modifiers ---
43	  it.todo("cursed sword (first contract) → cursed surcharge 50% applies");
44	  it.todo("sword enchantment 5 (first contract) → high-enchantment surcharge 30% applies");
45	  it.todo("sword enchantment 4 (first contract) → no high-enchantment surcharge");
46	  it.todo("cursed sword enchantment 5 → both surcharges apply");
47	
48	  // --- Policy-wide modifiers ---
49	  it.todo("customer 2 years → loyalty discount applies");
50	  it.todo("customer 1 year → no loyalty discount");
51	  it.todo("second contract → follow-up discount 15% applies");
52	
53	  // --- Modifier scope (item vs policy) ---
54	  it.todo("cursed sword + plain amulet → cursed surcharge applies to sword only; policy base 160, after curse 210 before fee");
55	
56	  // --- Rounding ---
57	  it.todo("premium yielding 197.5 G → rounded UP to 198 G");
58	
59	  // --- Integration examples ---
60	  it.todo("newcomer with cursed sword → premium 165 G");
61	  it.todo("long-standing customer's second contract with cursed enchanted sword → premium 160 G");
62	
63	  // --- Claim: standard reimbursement ---
64	  it.todo("steel sword enchantment 3, damage 500 G → payout 400 G (500 - 100 deductible)");
65	  it.todo("damage to rune (insurance 250 G), damage 200 G → payout 100 G");
66	
67	  // --- Claim: enchantment threshold ---
68	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
69	
70	  // --- Claim: dragon material ---
71	  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
72	
73	  // --- Claim: dragon + enchantment ---
74	  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
75	  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G");
76	
77	  // --- Deductible per damage event ---
78	  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (deductible per item)");
79	
80	  // --- Payout rounding ---
81	  it.todo("payout calc yielding 350.5 G → rounded DOWN to 350 G");
82	
83	  // --- Multiple items of same type ---
84	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
85	  it.todo("two swords damaged separately → each entry has own deductible");
86	  it.todo("damages array has more entries of a type than policy covers → CLI rejects (non-zero exit)");
87	
88	  // --- Cap exhaustion ---
89	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
90	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
91	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
92	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remainingCap 600");
93	  it.todo("sword (cap 2000), second claim 1500 after 1500 → payout 600, remainingCap 0");
94	
95	  // --- Edge cases ---
96	  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
97	  it.todo("claim references item not in policy → CLI exits non-zero");
98	  it.todo("claim with negative damage amount → CLI exits non-zero");
99	});
